const input = $input.first().json;
const headers = input.headers || {};
const auth = String(headers.authorization || headers.Authorization || '').trim();
const expected = 'Bearer ' + ($env.MKEN_WEBHOOK_TOKEN || 'CHANGE_ME');
const payload = input.body && typeof input.body === 'object' ? input.body : input;

if (auth !== expected) {
  return [{ json: { ok: false, error: 'Unauthorized', statusCode: 401 } }];
}

return [{ json: { ok: true, received: true, event: payload.event || null, to: payload.to || null, bodyPreview: String(payload.body || '').slice(0, 120), statusCode: 200 } }];
